package sn.gestionimmobiliere.backend.identity.api;import org.springframework.web.bind.annotation.*;import io.swagger.v3.oas.annotations.tags.Tag;import jakarta.validation.Valid;import sn.gestionimmobiliere.backend.identity.application.AuthService;@RestController @RequestMapping("/api/auth")@Tag(name="Authentication")public class AuthController{private final AuthService service;public AuthController(AuthService s){service=s;}@PostMapping("/login")public LoginResponse login(@Valid @RequestBody LoginRequest r){return service.login(r);}}
